def detect_kb_retrieval_gaps(session_history, kb_name):
    retrievals = []
    for turn in session_history['turns']:
        if 'retrievedReferences' in turn:
            docs = [ref['content']['text'] for ref in turn['retrievedReferences']]
            retrievals.extend(docs)

    # Check for expected enterprise docs that should appear
    expected_docs = ['policy-v1.pdf', 'pricing-2024.pdf']
    missing = [doc for doc in expected_docs if not any(doc in r for r in retrievals)]

    if missing:
        print(f'KB retrieval gap: Missing {missing} from {kb_name}')
        return False
    return True

import re

def scan_guardrail_violations(message):
    patterns = {
        'PII': r'\b(?:SSN|credit\s*card|passport)[^\.]*\d',
        'FINANCIAL': r'\b(?:\$|USD|account\s*number)[^\.]*\d{4,}',
        'CUSTOM_POLICY': r'\b(?:confidential|proprietary)[^\.]*\w+'
    }

    violations = []
    for policy, pattern in patterns.items():
        if re.search(pattern, message, re.IGNORECASE):
            violations.append(policy)

    if violations:
        print(f'Guardrail violation detected: {violations}')
        return False
    return True

