import boto3

bedrock_agent = boto3.client('bedrock-agent-runtime')

def invoke_agent_with_enhanced_kb(agent_id, session_id, input_text, kb_ids):
    # Force multiple KB retrieval passes
    params = {
        'agentId': agent_id,
        'sessionId': session_id,
        'inputText': input_text,
        'enableTrace': True,
        'knowledgeBaseConfiguration': {
            'knowledgeBaseIds': kb_ids,
            'retrievalConfiguration': {
                'vectorSearchConfiguration': {
                    'numberOfResults': 10,  # Increase results
                    'overrideSearchType': 'HYBRID'
                }
            }
        }
    }
    return bedrock_agent.invoke_agent(**params)

